import React, { useEffect, useState } from 'react';
import axios from 'axios';

function NotificationPanel() {
  const [notifications, setNotifications] = useState([]);
  const [error, setError] = useState('');
  const token = localStorage.getItem('token');

  useEffect(() => {
    axios.get('/api/notifications', {
      headers: { Authorization: `Bearer ${token}` }
    })
    .then(res => {
      if (res.data.success) {
        setNotifications(res.data.notifications);
      } else {
        setError(res.data.message);
      }
    })
    .catch(() => setError('Ошибка загрузки уведомлений'));
  }, []);

  const markAsRead = (id) => {
    axios.put(`/api/notifications/${id}/read`, {}, {
      headers: { Authorization: `Bearer ${token}` }
    }).then(() => {
      setNotifications(prev => prev.map(n => (
        n.id === id ? { ...n, is_read: true } : n
      )));
    });
  };

  const deleteNotification = (id) => {
    axios.delete(`/api/notifications/${id}`, {
      headers: { Authorization: `Bearer ${token}` }
    }).then(() => {
      setNotifications(prev => prev.filter(n => n.id !== id));
    });
  };

  return (
    <div className="p-4">
      <h4>🔔 Уведомления</h4>
      {error && <div className="alert alert-danger">{error}</div>}
      {notifications.length === 0 && <p>Нет уведомлений</p>}

      {notifications.map(n => (
        <div key={n.id} className={`alert ${n.is_read ? 'alert-secondary' : 'alert-primary'} d-flex justify-content-between align-items-start`}>
          <div>
            <strong>{n.title}</strong>
            <p className="mb-1">{n.message}</p>
            <small>{new Date(n.created_at).toLocaleString()}</small>
          </div>
          <div>
            {!n.is_read && (
              <button className="btn btn-sm btn-outline-success me-2" onClick={() => markAsRead(n.id)}>Прочитано</button>
            )}
            <button className="btn btn-sm btn-outline-danger" onClick={() => deleteNotification(n.id)}>Удалить</button>
          </div>
        </div>
      ))}
    </div>
  );
}

export default NotificationPanel;
